SELECT COUNT(*) FROM scatole

     AND statoDescrizione = #{stato} 

        AND (codiceScatola LIKE CONCAT('%', #{keyword}, '%') OR idDdtFK = #{keyword}) 

     AND dataCreazione >= #{startDate} 
     AND dataCreazione <= #{endDate} 
     AND idOperatoreFK = #{operatore}

SELECT s.*, m.idMazzetta, m.codiceMazzetta, m.posizione, m.numeroDocumenti, m.idScatolaFK, m.stato
FROM (
    SELECT * FROM scatole

         AND statoDescrizione = #{stato} 

            AND (codiceScatola LIKE CONCAT('%', #{keyword}, '%') OR idDdtFK = #{keyword}) 

         AND dataCreazione >= #{startDate} 
         AND dataCreazione <= #{endDate} 
        AND idOperatoreFK = #{operatore}

    ORDER BY ${orderBy} ${direzione}
    LIMIT #{pageSize} OFFSET #{offset}
) s
LEFT JOIN mazzette m ON s.idScatola = m.idScatolaFK
ORDER BY s.${orderBy} ${direzione}

